func TestHashJSONSuccessAndErrorSentinel(t *testing.T) {
	okHash := hashJSON(map[string]string{"a": "b"})
	if okHash == "" || isErrorHash(okHash) {
		t.Fatalf("expected normal hash, got=%s", okHash)
	}
	prev := marshalJSON
	marshalJSON = func(v interface{}) ([]byte, error) {
		return nil, errors.New("forced-marshal-error")
	}
	defer func() {
		marshalJSON = prev
	}()
	errHash := hashJSON(struct{}{})
	if errHash != "" {
		t.Fatalf("expected empty hash on marshal error, got=%s", errHash)
	}
	if _, ok := safeHash(struct{}{}); ok {
		t.Fatalf("safeHash should fail on marshal error")
	}
}
