func TestApplySoftFailureGuardBranches(t *testing.T) {
	base := time.Date(2026, 4, 3, 8, 0, 0, 0, time.UTC)
	svc := NewService(Config{Clock: func() time.Time {
		return base
	}, DecisionRetryLimitPerStep: 1})
	req := validRuntimeRequest()
	req.AttemptIndex = 0
	req.EvidenceFingerprint = "ev-1"
	resp := RuntimeDecisionResponse{DecisionID: "d-soft-1", Decision: DecisionReviewRequired, ReasonCodes: []string{"r1"}}
	got := svc.applySoftFailureGuard(req, resp, base)
	if got.Decision != DecisionReviewRequired {
		t.Fatalf("first soft failure should keep review_required")
	}
	got2 := svc.applySoftFailureGuard(req, resp, base.Add(time.Second))
	if got2.Decision != DecisionReviewRequired {
		t.Fatalf("second soft failure should still be review_required, got=%s", got2.Decision)
	}
	got3 := svc.applySoftFailureGuard(req, resp, base.Add(2*time.Second))
	if got3.Decision != DecisionFailed {
		t.Fatalf("third soft failure should exhaust to failed, got=%s", got3.Decision)
	}
	allowResp := RuntimeDecisionResponse{Decision: DecisionAllow}
	_ = svc.applySoftFailureGuard(req, allowResp, base.Add(3*time.Second))
	if len(svc.softFailures) != 0 {
		t.Fatalf("non-soft branch should clear soft failure state")
	}
	req.AttemptIndex = 2
	req.EvidenceFingerprint = "ev-2"
	_ = svc.applySoftFailureGuard(req, resp, base.Add(4*time.Second))
	before := svc.softFailures[req.TenantID+":"+req.RunID+":"+req.StepID].RetryCount
	_ = svc.applySoftFailureGuard(req, resp, base.Add(5*time.Second))
	after := svc.softFailures[req.TenantID+":"+req.RunID+":"+req.StepID].RetryCount
	if before != after {
		t.Fatalf("replayed same attempt index should not change retry count")
	}
}
