func structHasFields(v interface{}, names ...string) bool {
	rt := reflect.TypeOf(v)
	if rt == nil {
		return false
	}
	if rt.Kind() == reflect.Ptr {
		rt = rt.Elem()
	}
	if rt.Kind() != reflect.Struct {
		return false
	}
	for _, name := range names {
		if _, ok := rt.FieldByName(name); !ok {
			return false
		}
	}
	return true
}
