func TestScheduleAdmissionHashFailureMatrix(t *testing.T) {
	baseReq := ScheduleAdmissionRequest{RequestID: "req-sched-hash", RunID: "run-sched-hash", StepID: "step-sched-hash", TenantID: "tenant-sched-hash", RiskTier: RiskLow, RequestedResources: map[string]float64{"tokens": 1}, QuotaRemaining: map[string]float64{"tokens": 10}}
	t.Run("decision_id_hash_failure", func(t *testing.T) {
		orig := marshalJSON
		defer func() {
			marshalJSON = orig
		}()
		marshalJSON = func(v interface{}) ([]byte, error) {
			if structHasFields(v, "RequestID", "RunID", "StepID", "PriorityClass", "QuotaRemaining") {
				return nil, errors.New("forced decision id hash failure")
			}
			return json.Marshal(v)
		}
		svc := NewService(Config{})
		resp := svc.EvaluateScheduleAdmission(baseReq)
		if resp.Decision != DecisionDeny {
			t.Fatalf("expected deny, got=%s", resp.Decision)
		}
		if !containsString(resp.ReasonCodes, "decision_hash_invalid") {
			t.Fatalf("expected decision_hash_invalid reason code")
		}
		if !resp.DecisionHashIsFallback {
			t.Fatalf("decision hash should be marked fallback on decision id hash failure")
		}
		if strings.HasPrefix(resp.DecisionID, "dec_sched_err_") {
			t.Fatalf("decision id must not propagate err_ hash: %s", resp.DecisionID)
		}
	})
	t.Run("admission_hash_failure", func(t *testing.T) {
		orig := marshalJSON
		defer func() {
			marshalJSON = orig
		}()
		marshalJSON = func(v interface{}) ([]byte, error) {
			if structHasFields(v, "QueueClass", "Preemptable", "Decision", "ReasonCodes") {
				return nil, errors.New("forced admission decision hash failure")
			}
			return json.Marshal(v)
		}
		svc := NewService(Config{})
		resp := svc.EvaluateScheduleAdmission(baseReq)
		if resp.Decision != DecisionDeny {
			t.Fatalf("expected deny, got=%s", resp.Decision)
		}
		if resp.Ticket != nil {
			t.Fatalf("ticket must be nil on admission hash failure")
		}
		if !containsString(resp.ReasonCodes, "decision_hash_invalid") {
			t.Fatalf("expected decision_hash_invalid reason code")
		}
		if !resp.DecisionHashIsFallback {
			t.Fatalf("decision hash should be marked fallback on admission hash failure")
		}
	})
	t.Run("ticket_id_hash_failure", func(t *testing.T) {
		orig := marshalJSON
		defer func() {
			marshalJSON = orig
		}()
		marshalJSON = func(v interface{}) ([]byte, error) {
			if structHasFields(v, "RunID", "StepID", "DecisionHash") && !structHasFields(v, "RequestID") {
				return nil, errors.New("forced ticket id hash failure")
			}
			return json.Marshal(v)
		}
		svc := NewService(Config{})
		resp := svc.EvaluateScheduleAdmission(baseReq)
		if resp.Decision != DecisionDeny {
			t.Fatalf("expected deny, got=%s", resp.Decision)
		}
		if !containsString(resp.ReasonCodes, "ticket_id_hash_generation_failed") {
			t.Fatalf("expected ticket_id_hash_generation_failed")
		}
		if resp.Ticket != nil {
			t.Fatalf("ticket must be nil when ticket id hashing fails")
		}
		if resp.DecisionHashIsFallback {
			t.Fatalf("decision hash should remain canonical when ticket id generation fails")
		}
	})
}
