func TestDuplicateEvaluateDoesNotResetPendingState(t *testing.T) {
	now := time.Now()
	svc := NewService(Config{Clock: func() time.Time {
		return now
	}})
	req := validRuntimeRequest()
	resp := svc.EvaluateRuntime(req)
	_ = svc.ConfirmRunAdvance(ConfirmRunAdvanceRequest{DecisionID: resp.DecisionID, RunID: req.RunID, StepID: req.StepID, AttemptIndex: req.AttemptIndex, Phase: req.Phase, Success: true})
	p0 := *svc.pending[resp.DecisionID]
	now = now.Add(1 * time.Minute)
	resp2 := svc.EvaluateRuntime(req)
	if resp2.DecisionID != resp.DecisionID {
		t.Fatalf("same normalized runtime request should keep decision id stable")
	}
	p1 := svc.pending[resp.DecisionID]
	if p1.Status != pendingStatusConfirmed {
		t.Fatalf("duplicate evaluate must not reset confirmed to pending")
	}
	if !p1.CreatedAt.Equal(p0.CreatedAt) || p1.RepairAttempts != p0.RepairAttempts {
		t.Fatalf("duplicate evaluate must preserve created_at/repair_attempts")
	}
	events := svc.Outbox()
	dupSeen := false
	for _, e := range events {
		if e.EventType == eventPendingDuplicateEvaluate {
			dupSeen = true
			break
		}
	}
	if !dupSeen {
		t.Fatalf("expected pending duplicate evaluate event")
	}
	req2 := validRuntimeRequest()
	req2.RunID = "run-term"
	req2.StepID = "step-term"
	respTerm := svc.EvaluateRuntime(req2)
	term := svc.TerminalizePendingDecision(TerminalizePendingDecisionRequest{DecisionID: respTerm.DecisionID, Status: pendingStatusSafeguardHold})
	if term.Status != pendingStatusSafeguardHold {
		t.Fatalf("terminalize expected safeguard_hold, got=%+v", term)
	}
	now = now.Add(1 * time.Minute)
	_ = svc.EvaluateRuntime(req2)
	if svc.pending[respTerm.DecisionID].Status != pendingStatusSafeguardHold {
		t.Fatalf("duplicate evaluate must not reopen terminal pending status")
	}
}
