func TestRecordDecisionHistoryAndIdempotency(t *testing.T) {
	now := time.Now()
	svc := NewService(Config{Clock: func() time.Time {
		return now
	}})
	decisionID := "dec-history-1"
	req := map[string]interface{}{"request_id": "req-history"}
	resp1 := RuntimeDecisionResponse{DecisionID: decisionID, Decision: DecisionAllow, ReasonCodes: []string{"baseline_allow"}, DecisionHash: "h1"}
	svc.persistDecision("runtime", decisionID, req, resp1, now)
	d1, ok := svc.GetDecision(decisionID)
	if !ok {
		t.Fatalf("stored decision should exist")
	}
	if d1.Version != 1 {
		t.Fatalf("first decision version must be 1, got=%d", d1.Version)
	}
	if len(svc.decisionHistory[decisionID]) != 1 {
		t.Fatalf("history must start with one version")
	}
	svc.persistDecision("runtime", decisionID, req, resp1, now.Add(time.Second))
	if len(svc.decisionHistory[decisionID]) != 1 {
		t.Fatalf("identical rewrite must not append history")
	}
	d1b, _ := svc.GetDecision(decisionID)
	if d1b.Version != 1 {
		t.Fatalf("identical rewrite must keep version=1, got=%d", d1b.Version)
	}
	resp2 := resp1
	resp2.DecisionHash = "h2"
	resp2.ReasonCodes = []string{"policy_override"}
	svc.persistDecision("runtime", decisionID, req, resp2, now.Add(2*time.Second))
	d2, _ := svc.GetDecision(decisionID)
	if d2.Version != 2 {
		t.Fatalf("changed decision must bump version to 2, got=%d", d2.Version)
	}
	if len(svc.decisionHistory[decisionID]) != 2 {
		t.Fatalf("history should contain 2 versions, got=%d", len(svc.decisionHistory[decisionID]))
	}
}

