func hasFields(v interface{}, names ...string) bool {
	rv := reflect.ValueOf(v)
	if rv.Kind() == reflect.Ptr {
		if rv.IsNil() {
			return false
		}
		rv = rv.Elem()
	}
	if rv.Kind() != reflect.Struct {
		return false
	}
	rt := rv.Type()
	for _, name := range names {
		if _, ok := rt.FieldByName(name); !ok {
			return false
		}
	}
	return true
}
