func TestValidateExecutionReceiptBinding(t *testing.T) {
	now := time.Now()
	svc := NewService(Config{Clock: func() time.Time {
		return now
	}})
	admit := svc.EvaluateScheduleAdmission(ScheduleAdmissionRequest{RequestID: "adm-bind", RunID: "run-bind", StepID: "step-bind", TenantID: "tenant-bind", RiskTier: RiskLow, RequestedResources: map[string]float64{"tokens": 10}, QuotaRemaining: map[string]float64{"tokens": 20}})
	if admit.Ticket == nil {
		t.Fatalf("expected ticket")
	}
	missing := svc.ValidateExecutionReceipt(ExecutionReceipt{TicketID: admit.Ticket.TicketID, UsedResources: map[string]float64{"tokens": 1}, ReceivedAt: now})
	if missing.Accepted {
		t.Fatalf("missing binding should reject")
	}
	mismatch := svc.ValidateExecutionReceipt(ExecutionReceipt{TicketID: admit.Ticket.TicketID, RunID: "wrong", StepID: "step-bind", TenantID: "tenant-bind", UsedResources: map[string]float64{"tokens": 1}, ReceivedAt: now})
	if mismatch.Accepted {
		t.Fatalf("binding mismatch should reject")
	}
	ok := svc.ValidateExecutionReceipt(ExecutionReceipt{TicketID: admit.Ticket.TicketID, RunID: "run-bind", StepID: "step-bind", TenantID: "tenant-bind", UsedResources: map[string]float64{"tokens": 1}, ReceivedAt: now})
	if !ok.Accepted {
		t.Fatalf("binding match should pass: %+v", ok)
	}
	pass, reasons := svc.ValidateExecutionReceiptRef("run-bind", "step-bind", "tenant-bind", "ticket://"+admit.Ticket.TicketID)
	if !pass || len(reasons) != 0 {
		t.Fatalf("receipt ref validation should pass, reasons=%v", reasons)
	}
	pass, reasons = svc.ValidateExecutionReceiptRef("wrong", "step-bind", "tenant-bind", "ticket://"+admit.Ticket.TicketID)
	if pass || !hasReasonCode(reasons, "ticket_binding_mismatch") {
		t.Fatalf("receipt ref mismatch should reject, reasons=%v", reasons)
	}
	pass, reasons = svc.ValidateExecutionReceiptRef("run-bind", "step-bind", "tenant-bind", "rcpt://")
	if pass || !hasReasonCode(reasons, "execution_receipt_ticket_missing") {
		t.Fatalf("missing ticket in receipt ref should reject, reasons=%v", reasons)
	}
}

func TestExtractTicketIDFromExecutionReceiptRef(t *testing.T) {
	cases := []struct {
		ref  string
		want string
	}{
		{ref: "ticket://tk-1", want: "tk-1"},
		{ref: "ticket:tk-2", want: "tk-2"},
		{ref: "rcpt://tk-3", want: "tk-3"},
		{ref: "https://example.test/x?ticket_id=tk-4&x=1", want: "tk-4"},
		{ref: "https://example.test/x?ticket_id=tk-4b", want: "tk-4b"},
		{ref: "tk-5", want: "tk-5"},
		{ref: "receipt/path/no-ticket", want: ""},
	}
	for _, tc := range cases {
		if got := extractTicketIDFromExecutionReceiptRef(tc.ref); got != tc.want {
			t.Fatalf("extract ticket id mismatch: ref=%q got=%q want=%q", tc.ref, got, tc.want)
		}
	}
}

func TestValidateExecutionReceiptRefBranches(t *testing.T) {
	base := time.Date(2026, 4, 8, 9, 0, 0, 0, time.UTC)
	svc := NewService(Config{Clock: func() time.Time { return base }})
	admit := svc.EvaluateScheduleAdmission(ScheduleAdmissionRequest{
		RequestID:          "adm-ref-branch",
		RunID:              "run-ref",
		StepID:             "step-ref",
		TenantID:           "tenant-ref",
		RiskTier:           RiskLow,
		RequestedResources: map[string]float64{"tokens": 10},
		QuotaRemaining:     map[string]float64{"tokens": 20},
	})
	if admit.Ticket == nil {
		t.Fatalf("expected schedule ticket")
	}
	ok, reasons := svc.ValidateExecutionReceiptRef("", "step-ref", "tenant-ref", "ticket://"+admit.Ticket.TicketID)
	if ok || !hasReasonCode(reasons, "execution_binding_missing") {
		t.Fatalf("missing run binding should reject: ok=%v reasons=%v", ok, reasons)
	}
	ok, reasons = svc.ValidateExecutionReceiptRef("run-ref", "", "tenant-ref", "ticket://"+admit.Ticket.TicketID)
	if ok || !hasReasonCode(reasons, "execution_binding_missing") {
		t.Fatalf("missing step binding should reject: ok=%v reasons=%v", ok, reasons)
	}
	ok, reasons = svc.ValidateExecutionReceiptRef("run-ref", "step-ref", "", "ticket://"+admit.Ticket.TicketID)
	if !ok || len(reasons) != 0 {
		t.Fatalf("empty tenant should still pass when ticket binding matches: ok=%v reasons=%v", ok, reasons)
	}
	ok, reasons = svc.ValidateExecutionReceiptRef("run-ref", "step-ref", "tenant-wrong", "ticket://"+admit.Ticket.TicketID)
	if ok || !hasReasonCode(reasons, "ticket_binding_mismatch") {
		t.Fatalf("tenant mismatch should reject: ok=%v reasons=%v", ok, reasons)
	}
	ok, reasons = svc.ValidateExecutionReceiptRef("run-ref", "step-ref", "tenant-ref", "ticket://missing-ticket")
	if ok || !hasReasonCode(reasons, "ticket_not_found") {
		t.Fatalf("missing ticket should reject: ok=%v reasons=%v", ok, reasons)
	}

	svc.ticketMu.Lock()
	admit.Ticket.ExpiresAt = base.Add(-time.Second)
	svc.tickets[admit.Ticket.TicketID] = admit.Ticket
	svc.ticketMu.Unlock()
	ok, reasons = svc.ValidateExecutionReceiptRef("run-ref", "step-ref", "tenant-ref", "ticket://"+admit.Ticket.TicketID)
	if ok || !hasReasonCode(reasons, "ticket_expired") {
		t.Fatalf("expired ticket should reject: ok=%v reasons=%v", ok, reasons)
	}
}

