func TestCanExecuteSideEffectRequiresStableExecutableDecision(t *testing.T) {
	svc := NewService(Config{})
	req := validRuntimeRequest()
	req.RunID = "run-side-effect"
	req.StepID = "step-side-effect"
	resp := svc.EvaluateRuntime(req)
	if svc.CanExecuteSideEffect(resp.DecisionID) {
		t.Fatalf("must be blocked before confirm")
	}
	confirm := svc.ConfirmRunAdvance(ConfirmRunAdvanceRequest{
		DecisionID:   resp.DecisionID,
		RunID:        req.RunID,
		StepID:       req.StepID,
		AttemptIndex: req.AttemptIndex,
		Phase:        req.Phase,
		Success:      true,
	})
	if confirm.Status != pendingStatusConfirmed {
		t.Fatalf("confirm should produce confirmed status, got=%+v", confirm)
	}
	if !svc.CanExecuteSideEffect(resp.DecisionID) {
		t.Fatalf("confirmed allow decision should be executable")
	}

	svc.runtimeMu.Lock()
	d := svc.decisions[resp.DecisionID]
	d.DecisionHashIsFallback = true
	svc.decisions[resp.DecisionID] = d
	svc.runtimeMu.Unlock()
	if svc.CanExecuteSideEffect(resp.DecisionID) {
		t.Fatalf("fallback decision hash must not be executable")
	}

	svc.runtimeMu.Lock()
	d = svc.decisions[resp.DecisionID]
	d.DecisionHashIsFallback = false
	d.Response["decision"] = DecisionReviewRequired
	svc.decisions[resp.DecisionID] = d
	svc.runtimeMu.Unlock()
	if svc.CanExecuteSideEffect(resp.DecisionID) {
		t.Fatalf("review_required must not be executable")
	}
}

func TestCanExecuteSideEffectFinalRequiresRunAndReceiptGate(t *testing.T) {
	base := time.Date(2026, 4, 8, 10, 0, 0, 0, time.UTC)
	svc := NewKernel(Config{Clock: func() time.Time { return base }})
	runPort := &fakeRunStatePort{}
	svc.SetRunStatePort(runPort)
	req := validRuntimeRequest()
	req.RunID = "run-final-gate"
	req.StepID = "step-final-gate"
	runPort.setState(req.RunID, "RUNNING", base)
	resp := svc.EvaluateRuntime(req)
	allowed, reasons := svc.CanExecuteSideEffectFinal(SideEffectGateRequest{
		DecisionID:             resp.DecisionID,
		RunID:                  req.RunID,
		StepID:                 req.StepID,
		TenantID:               req.TenantID,
		RunState:               "RUNNING",
		ExecutionReceiptRef:    "ticket://missing",
		ExecutionUsedResources: map[string]float64{"tokens": 1},
		ExecutionReceiptAt:     base.Add(time.Second),
	})
	if allowed || !hasReasonCode(reasons, "decision_not_confirmed_or_not_executable") {
		t.Fatalf("unconfirmed decision must be blocked first: allowed=%v reasons=%v", allowed, reasons)
	}
	_ = svc.ConfirmRunAdvance(ConfirmRunAdvanceRequest{
		DecisionID:   resp.DecisionID,
		RunID:        req.RunID,
		StepID:       req.StepID,
		AttemptIndex: req.AttemptIndex,
		Phase:        req.Phase,
		Success:      true,
	})
	admit := svc.EvaluateScheduleAdmission(ScheduleAdmissionRequest{
		RequestID:          "adm-final-gate",
		RunID:              req.RunID,
		StepID:             req.StepID,
		TenantID:           req.TenantID,
		RiskTier:           req.RiskTier,
		RequestedResources: map[string]float64{"tokens": 10},
		QuotaRemaining:     map[string]float64{"tokens": 100},
	})
	if admit.Ticket == nil {
		t.Fatalf("expected ticket for final gate test")
	}
	runPort.setState(req.RunID, "PARKED", base.Add(2*time.Second))
	allowed, reasons = svc.CanExecuteSideEffectFinal(SideEffectGateRequest{
		DecisionID:             resp.DecisionID,
		RunID:                  req.RunID,
		StepID:                 req.StepID,
		TenantID:               req.TenantID,
		RunState:               "PARKED",
		ExecutionReceiptRef:    "ticket://" + admit.Ticket.TicketID,
		ExecutionUsedResources: map[string]float64{"tokens": 1},
		ExecutionReceiptAt:     base.Add(time.Second),
	})
	if allowed || !hasReasonCode(reasons, "run_state_not_running") {
		t.Fatalf("non-running run state must be blocked: allowed=%v reasons=%v", allowed, reasons)
	}
	runPort.setState(req.RunID, "RUNNING", base.Add(3*time.Second))
	allowed, reasons = svc.CanExecuteSideEffectFinal(SideEffectGateRequest{
		DecisionID:             resp.DecisionID,
		RunID:                  req.RunID,
		StepID:                 req.StepID,
		TenantID:               req.TenantID,
		RunState:               "RUNNING",
		ExecutionReceiptRef:    "ticket://" + admit.Ticket.TicketID,
		ExecutionUsedResources: map[string]float64{"tokens": 11},
		ExecutionReceiptAt:     base.Add(time.Second),
	})
	if allowed || !hasReasonCode(reasons, "resource_exceed_ticket") {
		t.Fatalf("exceeding usage should be blocked: allowed=%v reasons=%v", allowed, reasons)
	}
	allowed, reasons = svc.CanExecuteSideEffectFinal(SideEffectGateRequest{
		DecisionID:             resp.DecisionID,
		RunID:                  req.RunID,
		StepID:                 req.StepID,
		TenantID:               req.TenantID,
		RunState:               "RUNNING",
		ExecutionReceiptRef:    "ticket://" + admit.Ticket.TicketID,
		ExecutionUsedResources: map[string]float64{"tokens": 8},
		ExecutionReceiptAt:     base.Add(time.Second),
	})
	if !allowed || len(reasons) != 0 {
		t.Fatalf("expected strict final gate to pass: allowed=%v reasons=%v", allowed, reasons)
	}
}

