func TestEvaluateEnforcementBranches(t *testing.T) {
	gt := EnforcementThreshold{
		ObserveOnly:  0.0,
		Alert:        50,
		BlockRelease: 70,
		BlockRuntime: 90,
		Direction:    "gt",
	}
	if got := evaluateEnforcement("m", 0, false, gt); got != EnforcementMissing {
		t.Fatalf("missing metric should return missing, got=%s", got)
	}
	if got := evaluateEnforcement("m", 95, true, gt); got != EnforcementBlockRuntime {
		t.Fatalf("gt block runtime mismatch: %s", got)
	}
	if got := evaluateEnforcement("m", 75, true, gt); got != EnforcementBlockRelease {
		t.Fatalf("gt block release mismatch: %s", got)
	}
	if got := evaluateEnforcement("m", 55, true, gt); got != EnforcementAlert {
		t.Fatalf("gt alert mismatch: %s", got)
	}
	if got := evaluateEnforcement("m", 10, true, gt); got != EnforcementObserveOnly {
		t.Fatalf("gt observe mismatch: %s", got)
	}

	lt := EnforcementThreshold{
		ObserveOnly:  1.0,
		Alert:        0.8,
		BlockRelease: 0.5,
		BlockRuntime: 0.2,
		Direction:    "lt",
	}
	if got := evaluateEnforcement("m", 0.1, true, lt); got != EnforcementBlockRuntime {
		t.Fatalf("lt block runtime mismatch: %s", got)
	}
	if got := evaluateEnforcement("m", 0.4, true, lt); got != EnforcementBlockRelease {
		t.Fatalf("lt block release mismatch: %s", got)
	}
	if got := evaluateEnforcement("m", 0.7, true, lt); got != EnforcementAlert {
		t.Fatalf("lt alert mismatch: %s", got)
	}
	if got := evaluateEnforcement("m", 0.95, true, lt); got != EnforcementObserveOnly {
		t.Fatalf("lt observe mismatch: %s", got)
	}
}

func TestDispatchApprovalRunUnlockBranches(t *testing.T) {
	now := time.Date(2026, 4, 8, 11, 0, 0, 0, time.UTC)
	svc := NewKernel(Config{Clock: func() time.Time { return now }})
	signal := ApprovalRunUnlockSignal{
		CaseID:        "apc-1",
		RunID:         "run-1",
		StepID:        "step-1",
		DecisionID:    "dec-1",
		Outcome:       "approved",
		PendingStatus: pendingStatusConfirmed,
		ResolvedAt:    now,
	}
	status, reasons, result := svc.dispatchApprovalRunUnlock(signal, now)
	if status != "not_configured" || !hasReasonCode(reasons, "approval_run_unlock_not_configured") || result.DispatchStatus != "not_configured" {
		t.Fatalf("not configured branch mismatch: status=%s reasons=%v result=%+v", status, reasons, result)
	}

	port := &captureApprovalRunUnlockPort{
		result: ApprovalRunUnlockDispatchResult{
			DispatchStatus:            "queued",
			BusinessActionUnblocked:   false,
			BusinessActionUnblockedAt: time.Time{},
			ReasonCodes:               []string{"queued_for_async_resume"},
		},
	}
	svc.SetApprovalRunUnlockPort(port)
	status, reasons, result = svc.dispatchApprovalRunUnlock(signal, now)
	if status != "queued" || len(reasons) != 0 || !hasReasonCode(result.ReasonCodes, "queued_for_async_resume") {
		t.Fatalf("custom dispatch result mismatch: status=%s reasons=%v result=%+v", status, reasons, result)
	}
}
