type runtimeCaseFile struct {
	Cases []runtimeCase `json:"cases"`
}
type runtimeCase struct {
	Name    string                 `json:"name"`
	Request RuntimeDecisionRequest `json:"request"`
	Expect  runtimeExpect          `json:"expect"`
}
type runtimeExpect struct {
	Decision    string   `json:"decision"`
	ReasonCodes []string `json:"reason_codes"`
}

func TestEvaluateRuntime_FromTestData(t *testing.T) {
	svc := NewService(Config{})
	cases := loadRuntimeCases(t)
	for _, tc := range cases {
		tc := tc
		t.Run(tc.Name, func(t *testing.T) {
			resp := svc.EvaluateRuntime(tc.Request)
			if resp.Decision != tc.Expect.Decision {
				t.Fatalf("decision mismatch: got=%s want=%s", resp.Decision, tc.Expect.Decision)
			}
			if !sameStringSet(resp.ReasonCodes, tc.Expect.ReasonCodes) {
				t.Fatalf("reason_codes mismatch: got=%v want=%v", resp.ReasonCodes, tc.Expect.ReasonCodes)
			}
			if resp.DecisionID == "" || resp.DecisionHash == "" || resp.FrozenInputHash == "" {
				t.Fatalf("missing identifiers/hashes: %+v", resp)
			}
		})
	}
}
