func TestDecisionReferenceAndHashRefSemantics(t *testing.T) {
	svc := NewKernel(Config{})
	req := validRuntimeRequest()
	req.AttemptIndex = 2
	req.Phase = PhasePreResume
	resp := svc.EvaluateRuntime(req)
	ref, ok := svc.GetDecisionReference(resp.DecisionID)
	if !ok {
		t.Fatalf("decision reference not found")
	}
	if ref.DecisionHashRef.Kind != DecisionHashKindStable || !ref.DecisionHashRef.Valid {
		t.Fatalf("expected stable/valid hash ref, got=%+v", ref.DecisionHashRef)
	}
	if ref.RunID != req.RunID || ref.StepID != req.StepID || ref.AttemptIndex != req.AttemptIndex {
		t.Fatalf("unexpected decision binding in reference: %+v", ref)
	}
	svc.runtimeMu.Lock()
	d := svc.decisions[resp.DecisionID]
	d.DecisionHash = "dec_hash_seq_fallback"
	d.DecisionHashIsFallback = true
	svc.decisions[resp.DecisionID] = d
	svc.runtimeMu.Unlock()
	ref2, ok := svc.GetDecisionReference(resp.DecisionID)
	if !ok {
		t.Fatalf("decision reference missing after fallback mutation")
	}
	if ref2.DecisionHashRef.Valid || ref2.DecisionHashRef.Kind != DecisionHashKindFallback {
		t.Fatalf("fallback hash must be invalid for execution: %+v", ref2.DecisionHashRef)
	}
}
