func TestConfirmRunAdvanceOwnerClosure(t *testing.T) {
	svc := NewService(Config{})
	req := validRuntimeRequest()
	req.AttemptIndex = 2
	req.Phase = PhasePreTool
	resp := svc.EvaluateRuntime(req)
	missingOwner := svc.ConfirmRunAdvance(ConfirmRunAdvanceRequest{DecisionID: resp.DecisionID, RunID: req.RunID, StepID: req.StepID, Success: true})
	if !slices.Contains(missingOwner.ReasonCodes, "pending_owner_required") {
		t.Fatalf("expected pending_owner_required, got=%v", missingOwner.ReasonCodes)
	}
	badOwner := svc.ConfirmRunAdvance(ConfirmRunAdvanceRequest{DecisionID: resp.DecisionID, RunID: req.RunID, StepID: req.StepID, AttemptIndex: req.AttemptIndex, Phase: req.Phase, OwnerKey: "wrong|owner|0|PRE_TOOL", Success: true})
	if !slices.Contains(badOwner.ReasonCodes, "pending_owner_mismatch") {
		t.Fatalf("expected pending_owner_mismatch, got=%v", badOwner.ReasonCodes)
	}
	okOwner := svc.ConfirmRunAdvance(ConfirmRunAdvanceRequest{DecisionID: resp.DecisionID, RunID: req.RunID, StepID: req.StepID, AttemptIndex: req.AttemptIndex, Phase: req.Phase, Success: true})
	if okOwner.Status != pendingStatusConfirmed {
		t.Fatalf("expected confirmed with owner context, got=%s", okOwner.Status)
	}
	if !svc.IsDecisionConfirmedWithOwner(resp.DecisionID, req.RunID, req.StepID, req.AttemptIndex, req.Phase) {
		t.Fatalf("owner-aware confirm should succeed")
	}
	if svc.IsDecisionConfirmed(resp.DecisionID, req.RunID, req.StepID) {
		t.Fatalf("legacy confirm check should not bypass owner-bound pending")
	}
}
