func TestDecisionExtractionHelperCoverage(t *testing.T) {
	m := map[string]interface{}{
		"i":         3,
		"i64":       int64(4),
		"f":         5.7,
		"num":       json.Number("6"),
		"numf":      json.Number("7.2"),
		"str":       "8",
		"bad_str":   "x",
		"nil_value": nil,
	}
	if got := extractIntFieldFromMap(m, "i"); got != 3 {
		t.Fatalf("int extract mismatch: %d", got)
	}
	if got := extractIntFieldFromMap(m, "i64"); got != 4 {
		t.Fatalf("int64 extract mismatch: %d", got)
	}
	if got := extractIntFieldFromMap(m, "f"); got != 5 {
		t.Fatalf("float extract mismatch: %d", got)
	}
	if got := extractIntFieldFromMap(m, "num"); got != 6 {
		t.Fatalf("json.Number int extract mismatch: %d", got)
	}
	if got := extractIntFieldFromMap(m, "numf"); got != 7 {
		t.Fatalf("json.Number float extract mismatch: %d", got)
	}
	if got := extractIntFieldFromMap(m, "str"); got != 8 {
		t.Fatalf("string extract mismatch: %d", got)
	}
	if got := extractIntFieldFromMap(m, "bad_str"); got != 0 {
		t.Fatalf("bad string should map to 0, got=%d", got)
	}
	if got := extractIntFieldFromMap(m, "missing"); got != 0 {
		t.Fatalf("missing key should map to 0, got=%d", got)
	}

	obMap := map[string]interface{}{
		"obligations": []interface{}{
			map[string]interface{}{
				"type":       "attach_tag",
				"target":     "tier",
				"value":      "vip",
				"phase":      "pre_tool",
				"strictness": json.Number("9"),
			},
			map[string]interface{}{
				"type":  "emit_audit",
				"value": "audit_flag",
			},
			map[string]interface{}{
				"type":  "missing_value_should_drop",
				"value": "",
			},
			"not-a-map",
		},
	}
	obs := extractObligationsFromMap(obMap)
	if len(obs) != 2 {
		t.Fatalf("expected 2 valid obligations, got=%d (%+v)", len(obs), obs)
	}
	if obs[0].Phase != PhasePreTool {
		t.Fatalf("phase should normalize to uppercase, got=%s", obs[0].Phase)
	}
	if obs[0].Strictness != 9 {
		t.Fatalf("strictness should parse via helper, got=%d", obs[0].Strictness)
	}
	if got := extractStringFieldFromMap(map[string]interface{}{"n": json.Number("10")}, "n"); got != "10" {
		t.Fatalf("json number string extraction mismatch, got=%s", got)
	}
}

