func TestFeatureSignalContractScopedResolutionAndPriority(t *testing.T) {
	now := time.Date(2026, 4, 7, 21, 0, 0, 0, time.UTC)
	svc := NewKernel(Config{
		Clock: func() time.Time { return now },
		FeatureSignalContracts: map[string]FeatureSignalContract{
			"*|*": {RequiredFields: []string{"feature_version", "feature_evidence_ref", "feature_producer_id"}},
		},
	})

	scopeWorkspaceWildcard := ScopeRef{OrgID: "org-x", WorkspaceID: "ws-x", ProjectID: "*"}
	scopeExact := ScopeRef{OrgID: "org-x", WorkspaceID: "ws-x", ProjectID: "proj-a"}
	scopeOtherProject := ScopeRef{OrgID: "org-x", WorkspaceID: "ws-x", ProjectID: "proj-b"}

	_, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       "*",
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_evidence_ref"},
		Reason:         "scope-phase",
		Scope:          scopeWorkspaceWildcard,
	})
	if err != nil {
		t.Fatalf("publish workspace phase contract: %v", err)
	}
	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskHigh,
		Phase:          "*",
		RequiredFields: []string{"feature_version"},
		Reason:         "scope-risk",
		Scope:          scopeWorkspaceWildcard,
	})
	if err != nil {
		t.Fatalf("publish workspace risk contract: %v", err)
	}
	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskHigh,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_producer_id"},
		Reason:         "scope-exact",
		Scope:          scopeExact,
	})
	if err != nil {
		t.Fatalf("publish exact scope contract: %v", err)
	}

	c1, b1, ok := svc.resolveFeatureSignalContractWithBinding(scopeExact, RiskHigh, PhasePreTool, now)
	if !ok {
		t.Fatalf("expected exact scoped contract to resolve")
	}
	if len(c1.RequiredFields) != 1 || c1.RequiredFields[0] != "feature_producer_id" {
		t.Fatalf("unexpected exact contract fields: %+v", c1.RequiredFields)
	}
	if b1.ContractKey != "high|PRE_TOOL" {
		t.Fatalf("unexpected exact contract key: %s", b1.ContractKey)
	}
	if b1.StorageKey != featureSignalContractStorageKey(scopeExact, "high|PRE_TOOL") {
		t.Fatalf("unexpected exact storage key: %s", b1.StorageKey)
	}
	if len(b1.ResolutionPath) == 0 || b1.ResolutionPath[0] != featureSignalContractStorageKey(scopeExact, "high|PRE_TOOL") {
		t.Fatalf("resolution path should start with most specific candidate, got=%v", b1.ResolutionPath)
	}

	c2, b2, ok := svc.resolveFeatureSignalContractWithBinding(scopeOtherProject, RiskHigh, PhasePreTool, now)
	if !ok {
		t.Fatalf("expected scoped fallback contract to resolve")
	}
	// For the same scope candidate set, order must be: risk|phase -> risk|* -> *|phase -> *|*.
	// Since high|PRE_TOOL is absent on workspace wildcard scope, high|* must win before *|PRE_TOOL.
	if len(c2.RequiredFields) != 1 || c2.RequiredFields[0] != "feature_version" {
		t.Fatalf("expected risk|* fallback contract, got fields=%+v key=%s", c2.RequiredFields, b2.ContractKey)
	}
	if b2.ContractKey != "high|*" {
		t.Fatalf("expected high|* winner, got=%s", b2.ContractKey)
	}
	wantPrefix := []string{
		featureSignalContractStorageKey(scopeOtherProject, "high|PRE_TOOL"),
		featureSignalContractStorageKey(scopeOtherProject, "high|*"),
		featureSignalContractStorageKey(scopeOtherProject, "*|PRE_TOOL"),
		featureSignalContractStorageKey(scopeOtherProject, "*|*"),
	}
	if len(b2.ResolutionPath) < len(wantPrefix) {
		t.Fatalf("resolution path too short: %v", b2.ResolutionPath)
	}
	for i := range wantPrefix {
		if b2.ResolutionPath[i] != wantPrefix[i] {
			t.Fatalf("resolution order mismatch at %d: got=%s want=%s full=%v", i, b2.ResolutionPath[i], wantPrefix[i], b2.ResolutionPath)
		}
	}
}

func TestRuntimeFeatureSignalContractHashPinningAndEvidenceBinding(t *testing.T) {
	now := time.Date(2026, 4, 7, 21, 30, 0, 0, time.UTC)
	scope := ScopeRef{OrgID: "org-pin", WorkspaceID: "ws-pin", ProjectID: "proj-pin"}
	svc := NewKernel(Config{
		Clock: func() time.Time { return now },
		FeatureSignalContracts: map[string]FeatureSignalContract{
			"*|*": {RequiredFields: []string{"feature_version", "feature_evidence_ref", "feature_producer_id"}},
		},
	})
	_, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version", "feature_evidence_ref"},
		Reason:         "pin-test",
		Scope:          scope,
	})
	if err != nil {
		t.Fatalf("publish scoped contract: %v", err)
	}
	view, ok := svc.GetFeatureSignalContractForScope(RiskLow, PhasePreTool, scope)
	if !ok {
		t.Fatalf("expected scoped contract view")
	}
	if view.Version <= 0 || strings.TrimSpace(view.ContractHash) == "" {
		t.Fatalf("contract view should expose version/hash: %+v", view)
	}

	req := validRuntimeRequest()
	req.RiskTier = RiskLow
	req.EffectType = EffectRead
	req.FeatureContractScope = scope
	req.FeatureContractHashPin = view.ContractHash
	req.FeatureVersion = "fv-pin-1"
	req.FeatureEvidenceRef = "evidence://feature/fv-pin-1"
	req.FeatureProducerID = "feature-producer-default"

	okResp := svc.EvaluateRuntime(req)
	if okResp.Decision == DecisionFailClosed && slices.Contains(okResp.ReasonCodes, "feature_signal_contract_hash_pin_mismatch") {
		t.Fatalf("pin match should not fail closed: %+v", okResp)
	}
	if okResp.FeatureContractBinding.ContractKey != "low|PRE_TOOL" {
		t.Fatalf("unexpected resolved contract key: %s", okResp.FeatureContractBinding.ContractKey)
	}
	if okResp.FeatureContractBinding.Version != view.Version || okResp.FeatureContractBinding.ContractHash != view.ContractHash {
		t.Fatalf("binding should carry resolved version/hash, got=%+v wantVersion=%d wantHash=%s", okResp.FeatureContractBinding, view.Version, view.ContractHash)
	}

	events := svc.Outbox()
	runtimeEventPayload := lastDecisionEventPayloadByType(events, eventDecisionRuntimeEvaluated)
	if runtimeEventPayload == nil {
		t.Fatalf("expected runtime evaluated event payload")
	}
	if _, ok := runtimeEventPayload["contract_version"]; !ok {
		t.Fatalf("runtime event must include contract_version: payload=%v", runtimeEventPayload)
	}
	if _, ok := runtimeEventPayload["contract_hash"]; !ok {
		t.Fatalf("runtime event must include contract_hash: payload=%v", runtimeEventPayload)
	}
	hashReq := req
	hashReq.RequestID = "req-pin-hash-mismatch"
	hashReq.FeatureContractHashPin = "not-the-right-hash"
	hashResp := svc.EvaluateRuntime(hashReq)
	if hashResp.Decision != DecisionFailClosed {
		t.Fatalf("hash pin mismatch must fail closed, got=%s", hashResp.Decision)
	}
	if !slices.Contains(hashResp.ReasonCodes, "feature_signal_contract_hash_pin_mismatch") {
		t.Fatalf("missing hash pin mismatch reason: %v", hashResp.ReasonCodes)
	}
	events = svc.Outbox()
	missingPayload := lastDecisionEventPayloadByType(events, eventFeatureSignalContractMissing)
	if missingPayload == nil {
		t.Fatalf("expected feature_signal_contract_missing event payload")
	}
	if missingPayload["pin_type"] != "hash" {
		t.Fatalf("expected pin_type=hash in mismatch event, got=%v", missingPayload["pin_type"])
	}
	if _, ok := missingPayload["contract_resolution_path"]; !ok {
		t.Fatalf("missing contract_resolution_path in mismatch event payload: %v", missingPayload)
	}
}

func TestExtractDecisionHashRefBranchCoverage(t *testing.T) {
	// explicit kind + invalid should preserve kind/invalid
	ref := extractDecisionHashRef(RuntimeDecisionResponse{
		DecisionHash:           "h1",
		DecisionHashIsFallback: false,
		DecisionHashRef:        DecisionHashRef{Value: "h1", Valid: false, Kind: DecisionHashKindStable},
	})
	if ref.Valid || ref.Kind != DecisionHashKindStable {
		t.Fatalf("expected stable+invalid, got=%+v", ref)
	}

	// explicit kind + valid + empty value should degrade to error
	ref = extractDecisionHashRef(RuntimeDecisionResponse{
		DecisionHash:           "",
		DecisionHashIsFallback: false,
		DecisionHashRef:        DecisionHashRef{Value: "", Valid: true, Kind: DecisionHashKindStable},
	})
	if ref.Valid || ref.Kind != DecisionHashKindError {
		t.Fatalf("empty value with valid kind must degrade to error, got=%+v", ref)
	}

	// fallback must always become invalid fallback-kind
	ref = extractDecisionHashRef(&ScheduleAdmissionResponse{
		DecisionHash:           "sched_fb",
		DecisionHashIsFallback: true,
		DecisionHashRef:        DecisionHashRef{Value: "", Valid: true, Kind: ""},
	})
	if ref.Valid || ref.Kind != DecisionHashKindFallback {
		t.Fatalf("fallback response should produce fallback kind, got=%+v", ref)
	}

	// unknown payload with error hash should map to error kind
	ref = extractDecisionHashRef(map[string]interface{}{})
	if ref.Valid || ref.Kind != DecisionHashKindError {
		t.Fatalf("unknown response must map to invalid error ref, got=%+v", ref)
	}
}

func TestBuildObligationPlanApprovalWeakeningConflict(t *testing.T) {
	preTool := []Obligation{
		{Type: "limit_param", Target: "amount", Value: "max:100", Phase: PhasePreTool, Strictness: 80},
	}
	approval := []Obligation{
		{Type: "limit_param", Target: "amount", Value: "max:120", Phase: PhasePreResume, Strictness: 70}, // weaker, should be rejected
		{Type: "attach_tag", Target: "channel", Value: "manual", Phase: PhasePreResume, Strictness: 90},  // new key, should be accepted
	}
	plan := BuildObligationPlan(preTool, nil, approval)
	if !slices.Contains(plan.Conflicts, "approval_obligation_weaken_forbidden") {
		t.Fatalf("expected approval weaken conflict, got=%v", plan.Conflicts)
	}
	foundAmount := false
	foundChannel := false
	for _, ob := range plan.Obligations {
		if ob.Type == "limit_param" && ob.Target == "amount" {
			foundAmount = true
			if ob.Strictness != 80 {
				t.Fatalf("weakened approval must not override existing strictness, got=%d", ob.Strictness)
			}
		}
		if ob.Type == "attach_tag" && ob.Target == "channel" {
			foundChannel = true
		}
	}
	if !foundAmount || !foundChannel {
		t.Fatalf("expected retained amount and appended channel obligations: %+v", plan.Obligations)
	}
}

func TestSoftFailureStageStrongEnumJSON(t *testing.T) {
	stage := SoftFailureStageRetrying
	raw, err := json.Marshal(stage)
	if err != nil {
		t.Fatalf("marshal stage: %v", err)
	}
	if string(raw) != `"retrying"` {
		t.Fatalf("unexpected marshaled stage: %s", string(raw))
	}

	var decoded SoftFailureStage
	if err := json.Unmarshal([]byte(`"exhausted"`), &decoded); err != nil {
		t.Fatalf("unmarshal stage: %v", err)
	}
	if decoded != SoftFailureStageExhausted {
		t.Fatalf("unexpected decoded stage: %v", decoded)
	}
	if _, ok := ParseSoftFailureStage("bad-stage"); ok {
		t.Fatalf("invalid stage should not parse")
	}
	if err := json.Unmarshal([]byte(`"bad-stage"`), &decoded); err == nil {
		t.Fatalf("invalid stage json should fail")
	}
	invalid := SoftFailureStage(200)
	if _, err := json.Marshal(invalid); err == nil {
		t.Fatalf("invalid enum value should fail marshal")
	}
}

