func TestDecisionHelperEdgeCoverage(t *testing.T) {
	// extractDecisionHashRef nil-pointer branches
	if ref := extractDecisionHashRef((*RuntimeDecisionResponse)(nil)); ref.Valid || ref.Kind != DecisionHashKindError {
		t.Fatalf("nil runtime response should produce error ref, got=%+v", ref)
	}
	if ref := extractDecisionHashRef((*ScheduleAdmissionResponse)(nil)); ref.Valid || ref.Kind != DecisionHashKindError {
		t.Fatalf("nil schedule response should produce error ref, got=%+v", ref)
	}
	if ref := extractDecisionHashRef((*ReleaseDecisionResponse)(nil)); ref.Valid || ref.Kind != DecisionHashKindError {
		t.Fatalf("nil release response should produce error ref, got=%+v", ref)
	}

	// unknown payload fallback path should degrade to error when no typed hash extractor applies.
	ref := extractDecisionHashRef(map[string]interface{}{
		"decision_hash":             "h-fallback",
		"decision_hash_is_fallback": true,
	})
	if ref.Valid || ref.Kind != DecisionHashKindError {
		t.Fatalf("unknown payload with untyped hash should degrade to error ref: %+v", ref)
	}

	// canonicalization should drop volatile hash keys and handle marshal errors.
	sem := canonicalizeForDecisionSemantic(map[string]interface{}{
		"a":                         1,
		"decision_hash":             "x",
		"decision_hash_is_fallback": true,
		"decision_hash_ref":         map[string]interface{}{"kind": "stable"},
	})
	if strings.Contains(sem, "decision_hash") {
		t.Fatalf("semantic canonicalization should strip hash fields, got=%s", sem)
	}
	if got := canonicalizeForDecisionSemantic(map[string]interface{}{"bad": make(chan int)}); got != "{}" {
		t.Fatalf("marshal failure should canonicalize to empty object, got=%s", got)
	}

	// uniqueStrings dedupe branch.
	uniq := uniqueStrings([]string{"a", "a", "b", "b", "c"})
	if len(uniq) != 3 {
		t.Fatalf("unexpected uniqueStrings result: %+v", uniq)
	}
}

func TestFeatureSignalContractHelperCoverage(t *testing.T) {
	if got := normalizeContractKey("", ""); got != "*|*" {
		t.Fatalf("normalize empty contract key mismatch: %s", got)
	}
	if got := normalizeContractKey(" HIGH ", "pre_tool"); got != "high|PRE_TOOL" {
		t.Fatalf("normalize contract key mismatch: %s", got)
	}
	if rt, phase := splitContractKey(""); rt != "*" || phase != "*" {
		t.Fatalf("split empty key mismatch: rt=%s phase=%s", rt, phase)
	}
	if rt, phase := splitContractKey("low"); rt != "low" || phase != "*" {
		t.Fatalf("split one-part key mismatch: rt=%s phase=%s", rt, phase)
	}
	if rt, phase := splitContractKey("high|PRE_TOOL"); rt != "high" || phase != "PRE_TOOL" {
		t.Fatalf("split two-part key mismatch: rt=%s phase=%s", rt, phase)
	}
	fields := normalizeRequiredFields([]string{" feature_version ", "", "feature_version", "FEATURE_PRODUCER_ID"})
	if len(fields) != 2 || fields[0] != "feature_producer_id" || fields[1] != "feature_version" {
		t.Fatalf("normalize required fields mismatch: %+v", fields)
	}
	if err := validateFeatureSignalContractRequiredFields([]string{}); err == nil {
		t.Fatalf("empty required_fields should fail")
	}
	if err := validateFeatureSignalContractRequiredFields([]string{"feature_version", "x"}); err == nil {
		t.Fatalf("unsupported required_fields should fail")
	}
	if err := validateFeatureSignalContractRequiredFields([]string{"feature_version"}); err != nil {
		t.Fatalf("valid required_fields should pass: %v", err)
	}
	if err := validateFeatureSignalContractRequiredFields([]string{"feature_schema_version"}); err != nil {
		t.Fatalf("feature_schema_version should be accepted: %v", err)
	}
	if m, ok := schemaMajor("v2.1.0"); !ok || m != 2 {
		t.Fatalf("schemaMajor parse mismatch: m=%d ok=%v", m, ok)
	}
	if _, ok := schemaMajor("invalid"); ok {
		t.Fatalf("schemaMajor should reject invalid input")
	}
	if !isSchemaBreakingChange("v1.2.0", "v2.0.0") {
		t.Fatalf("expected schema breaking change on major bump")
	}
	if isSchemaBreakingChange("v1.2.0", "v1.9.0") {
		t.Fatalf("unexpected schema breaking change on same major")
	}
	producers := normalizeTrustedProducerIDs([]string{" p2 ", "p1", "p1", ""})
	if len(producers) != 2 || producers[0] != "p1" || producers[1] != "p2" {
		t.Fatalf("normalizeTrustedProducerIDs mismatch: %+v", producers)
	}
}

