func TestFeatureSignalContractPublishSafetyAndResolutionBranchCoverage(t *testing.T) {
	now := time.Date(2026, 4, 7, 22, 0, 0, 0, time.UTC)
	scope := ScopeRef{OrgID: "org-safety", WorkspaceID: "ws-safety", ProjectID: "proj-safety"}
	svc := NewKernel(Config{
		Clock: func() time.Time { return now },
		FeatureSignalContracts: map[string]FeatureSignalContract{
			"*|*": {RequiredFields: []string{"feature_version"}},
		},
	})

	if got := normalizeContractScope(ScopeRef{}); got.OrgID != "*" || got.WorkspaceID != "*" || got.ProjectID != "*" {
		t.Fatalf("empty scope should normalize to global wildcard, got=%+v", got)
	}
	if got := normalizeContractScope(ScopeRef{OrgID: "org", WorkspaceID: "", ProjectID: "proj"}); got.OrgID != "org" || got.WorkspaceID != "*" || got.ProjectID != "proj" {
		t.Fatalf("partial scope wildcard fill mismatch, got=%+v", got)
	}
	keys := contractKeyResolutionOrder("", "")
	if len(keys) != 4 || keys[0] != "*|*" || keys[3] != "*|*" {
		t.Fatalf("unexpected contract key resolution order for empty input: %v", keys)
	}
	if rt, phase := splitContractKey("onlyrisk|"); rt != "onlyrisk" || phase != "*" {
		t.Fatalf("split contract key with empty phase mismatch: rt=%s phase=%s", rt, phase)
	}

	v1, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version", "feature_evidence_ref"},
		Reason:         "v1",
		Scope:          scope,
	})
	if err != nil {
		t.Fatalf("publish v1: %v", err)
	}
	if v1.Version <= 0 {
		t.Fatalf("expected positive contract version, got=%d", v1.Version)
	}

	dryRun, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version", "feature_evidence_ref", "feature_producer_id"},
		Reason:         "dry-run-expand",
		Scope:          scope,
		DryRun:         true,
	})
	if err != nil {
		t.Fatalf("dry-run publish should pass: %v", err)
	}
	if dryRun.Version != v1.Version+1 {
		t.Fatalf("dry-run should preview next version, got=%d want=%d", dryRun.Version, v1.Version+1)
	}
	historyBefore, ok := svc.GetFeatureSignalContractHistoryForScope(RiskLow, PhasePreTool, scope, 20)
	if !ok || len(historyBefore) == 0 {
		t.Fatalf("history must exist before/after dry-run, ok=%v len=%d", ok, len(historyBefore))
	}
	if historyBefore[len(historyBefore)-1].Version != v1.Version {
		t.Fatalf("dry-run must not persist new history version, got latest=%d want=%d", historyBefore[len(historyBefore)-1].Version, v1.Version)
	}

	v2, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version", "feature_evidence_ref", "feature_producer_id"},
		Reason:         "v2",
		Scope:          scope,
	})
	if err != nil {
		t.Fatalf("publish v2: %v", err)
	}
	if v2.Version != v1.Version+1 {
		t.Fatalf("version should increase after real publish, got=%d want=%d", v2.Version, v1.Version+1)
	}
	if !sameStringSet(v2.RequiredFields, []string{"feature_evidence_ref", "feature_producer_id", "feature_version"}) {
		t.Fatalf("latest publish should overwrite current required fields, got=%v", v2.RequiredFields)
	}

	// Rollback branch: no previous version should fail on a one-version contract.
	scopeSingle := ScopeRef{OrgID: "org-safety", WorkspaceID: "ws-safety", ProjectID: "single"}
	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskMedium,
		Phase:          PhasePreResume,
		RequiredFields: []string{"feature_version"},
		Reason:         "single-v1",
		Scope:          scopeSingle,
	})
	if err != nil {
		t.Fatalf("publish single v1: %v", err)
	}
	if _, err := svc.RollbackFeatureSignalContract(FeatureSignalContractRollbackRequest{
		RiskTier: RiskMedium,
		Phase:    PhasePreResume,
		Reason:   "no-prev",
		Scope:    scopeSingle,
	}); err == nil {
		t.Fatalf("rollback without previous version should fail")
	}

	// Validate branch coverage for required fields/risk/phase.
	validate := svc.ValidateFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version"},
		Reason:         "validate",
	})
	if !validate.Valid {
		t.Fatalf("validate should pass with valid contract checks")
	}
	validateBad := svc.ValidateFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"bad_field"},
		Reason:         "validate-bad",
	})
	if validateBad.Valid {
		t.Fatalf("validate should fail with invalid required_fields")
	}

	// Resolver branch: no scoped contract set and no bootstrapped required fields => found=false fallback.
	svcNoContracts := NewKernel(Config{
		Clock: func() time.Time { return now },
		FeatureSignalContracts: map[string]FeatureSignalContract{
			"*|*": {RequiredFields: nil},
		},
	})
	_, binding, found := svcNoContracts.resolveFeatureSignalContractWithBinding(scope, RiskHigh, PhasePreRelease, now)
	if found {
		t.Fatalf("expected found=false when no required-field contracts exist")
	}
	if len(binding.RequiredFields) == 0 {
		t.Fatalf("fallback binding should still expose default required fields")
	}
}

func TestFeatureSignalContractCompatibilityAndScheduledActivation(t *testing.T) {
	now := time.Date(2026, 4, 7, 22, 0, 0, 0, time.UTC)
	scope := ScopeRef{OrgID: "org-compat", WorkspaceID: "ws-compat", ProjectID: "proj-compat"}
	svc := NewKernel(Config{
		Clock: func() time.Time { return now },
	})

	v1, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version", "feature_evidence_ref"},
		Reason:         "seed",
		Scope:          scope,
	})
	if err != nil {
		t.Fatalf("publish v1: %v", err)
	}
	if v1.Status != "active" {
		t.Fatalf("expected active v1 status, got=%s", v1.Status)
	}

	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version"},
		Reason:         "breaking-without-allow",
		Scope:          scope,
	})
	if err == nil {
		t.Fatalf("expected breaking change rejection when allow_breaking_change=false")
	}

	activateAt := now.Add(30 * time.Minute)
	v2, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:            RiskLow,
		Phase:               PhasePreTool,
		RequiredFields:      []string{"feature_version", "feature_evidence_ref", "feature_producer_id"},
		Reason:              "scheduled-expand",
		Scope:               scope,
		AllowBreakingChange: true,
		ActivateAt:          activateAt,
	})
	if err != nil {
		t.Fatalf("publish scheduled v2: %v", err)
	}
	if v2.Status != "scheduled" {
		t.Fatalf("expected scheduled status before activation, got=%s", v2.Status)
	}

	current, ok := svc.GetFeatureSignalContractForScope(RiskLow, PhasePreTool, scope)
	if !ok {
		t.Fatalf("expected active contract for scope")
	}
	if current.Version != v1.Version || current.Status != "active" {
		t.Fatalf("scheduled publish should not switch active immediately, got version=%d status=%s", current.Version, current.Status)
	}

	now = activateAt.Add(1 * time.Second)
	sched := svc.RunFeatureSignalContractScheduler(now)
	if sched.Activated == 0 {
		t.Fatalf("expected scheduler to activate due contracts")
	}

	after, ok := svc.GetFeatureSignalContractForScope(RiskLow, PhasePreTool, scope)
	if !ok {
		t.Fatalf("expected contract after activation")
	}
	if after.Version != v2.Version || after.Status != "active" {
		t.Fatalf("expected scheduled version to activate, got version=%d status=%s", after.Version, after.Status)
	}

	history, ok := svc.GetFeatureSignalContractHistoryForScope(RiskLow, PhasePreTool, scope, 10)
	if !ok || len(history) < 2 {
		t.Fatalf("expected history after activation, ok=%v len=%d", ok, len(history))
	}
	latest := history[len(history)-1]
	if latest.Status != "active" {
		t.Fatalf("latest history version must be active after activation, got=%s", latest.Status)
	}
}

