func TestFeatureSignalContractPrecedenceScopeThenKeyInvariant(t *testing.T) {
	now := time.Date(2026, 4, 8, 2, 0, 0, 0, time.UTC)
	svc := NewKernel(Config{
		Clock: func() time.Time { return now },
	})
	scopeOrg := ScopeRef{OrgID: "org-pri", WorkspaceID: "*", ProjectID: "*"}
	scopeWorkspace := ScopeRef{OrgID: "org-pri", WorkspaceID: "ws-pri", ProjectID: "*"}
	scopeProject := ScopeRef{OrgID: "org-pri", WorkspaceID: "ws-pri", ProjectID: "proj-pri"}

	// global exact
	_, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskHigh,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version"},
		Reason:         "global-exact",
		Scope:          globalContractScope(),
	})
	if err != nil {
		t.Fatalf("publish global exact: %v", err)
	}
	// org exact
	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskHigh,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_evidence_ref"},
		Reason:         "org-exact",
		Scope:          scopeOrg,
	})
	if err != nil {
		t.Fatalf("publish org exact: %v", err)
	}
	// workspace exact
	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskHigh,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_producer_id"},
		Reason:         "workspace-exact",
		Scope:          scopeWorkspace,
	})
	if err != nil {
		t.Fatalf("publish workspace exact: %v", err)
	}
	// project wildcard key
	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskHigh,
		Phase:          "*",
		RequiredFields: []string{"feature_schema_version"},
		Reason:         "project-risk-wildcard",
		Scope:          scopeProject,
	})
	if err != nil {
		t.Fatalf("publish project risk wildcard: %v", err)
	}

	// Invariant: scope precedence is evaluated before key specificity.
	contract, binding, found := svc.resolveFeatureSignalContractWithBinding(scopeProject, RiskHigh, PhasePreTool, now)
	if !found {
		t.Fatalf("expected contract resolution")
	}
	if binding.ScopeMatchLevel != "project" {
		t.Fatalf("expected project scope match level, got=%s", binding.ScopeMatchLevel)
	}
	if binding.ContractKey != "high|*" || binding.KeyMatchLevel != "risk_wildcard" {
		t.Fatalf("expected project high|* winner before workspace/org/global exact, got key=%s level=%s", binding.ContractKey, binding.KeyMatchLevel)
	}
	if len(contract.RequiredFields) != 1 || contract.RequiredFields[0] != "feature_schema_version" {
		t.Fatalf("unexpected resolved project wildcard contract fields: %+v", contract.RequiredFields)
	}

	// Add project exact and verify exact wins within the same highest-priority scope.
	_, err = svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskHigh,
		Phase:          PhasePreTool,
		RequiredFields: []string{"feature_version", "feature_schema_version"},
		Reason:         "project-exact",
		Scope:          scopeProject,
	})
	if err != nil {
		t.Fatalf("publish project exact: %v", err)
	}
	contract2, binding2, found2 := svc.resolveFeatureSignalContractWithBinding(scopeProject, RiskHigh, PhasePreTool, now)
	if !found2 {
		t.Fatalf("expected contract resolution after project exact")
	}
	if binding2.ScopeMatchLevel != "project" || binding2.KeyMatchLevel != "exact" || binding2.ContractKey != "high|PRE_TOOL" {
		t.Fatalf("expected project exact winner, got scope=%s key=%s level=%s", binding2.ScopeMatchLevel, binding2.ContractKey, binding2.KeyMatchLevel)
	}
	if !sameStringSet(contract2.RequiredFields, []string{"feature_version", "feature_schema_version"}) {
		t.Fatalf("unexpected project exact fields: %+v", contract2.RequiredFields)
	}
}

func TestFeatureSignalContractCacheWatcherSyncAcrossKernels(t *testing.T) {
	now := time.Date(2026, 4, 8, 2, 10, 0, 0, time.UTC)
	store := NewInMemoryFeatureSignalContractStore(32, FeatureSignalContractStoreSnapshot{})
	k1 := NewKernel(Config{
		Clock:                      func() time.Time { return now },
		FeatureSignalContractStore: store,
	})
	k2 := NewKernel(Config{
		Clock:                      func() time.Time { return now },
		FeatureSignalContractStore: store,
	})

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	if err := k2.StartFeatureSignalContractCacheWatcher(ctx); err != nil {
		t.Fatalf("start contract cache watcher: %v", err)
	}
	defer k2.StopFeatureSignalContractCacheWatcher()

	scope := ScopeRef{OrgID: "org-sync", WorkspaceID: "ws-sync", ProjectID: "proj-sync"}
	published, err := k1.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:           RiskHigh,
		Phase:              PhasePreTool,
		RequiredFields:     []string{"feature_version", "feature_evidence_ref", "feature_producer_id"},
		SchemaVersion:      "v3.0.0",
		TrustedProducerIDs: []string{"producer-sync"},
		MaxFreshnessMS:     1500,
		MaxDriftScore:      0.3,
		Reason:             "watch-sync",
		Scope:              scope,
	})
	if err != nil {
		t.Fatalf("publish on writer kernel: %v", err)
	}

	deadline := time.Now().Add(1200 * time.Millisecond)
	for time.Now().Before(deadline) {
		view, ok := k2.GetFeatureSignalContractForScope(RiskHigh, PhasePreTool, scope)
		if ok && view.Version == published.Version && view.ContractHash == published.ContractHash {
			return
		}
		time.Sleep(10 * time.Millisecond)
	}
	view, ok := k2.GetFeatureSignalContractForScope(RiskHigh, PhasePreTool, scope)
	if !ok {
		t.Fatalf("watcher sync timeout: reader kernel did not observe published contract")
	}
	t.Fatalf("watcher sync mismatch: got version=%d hash=%s, want version=%d hash=%s", view.Version, view.ContractHash, published.Version, published.ContractHash)
}

