type failingFeatureSignalContractStore struct {
	getErr   error
	putErr   error
	watchErr error
}

func (f failingFeatureSignalContractStore) GetSnapshot(ctx context.Context) (FeatureSignalContractStoreSnapshot, error) {
	if f.getErr != nil {
		return FeatureSignalContractStoreSnapshot{}, f.getErr
	}
	return FeatureSignalContractStoreSnapshot{}, nil
}

func (f failingFeatureSignalContractStore) PutSnapshot(ctx context.Context, snapshot FeatureSignalContractStoreSnapshot) (FeatureSignalContractStoreSnapshot, error) {
	if f.putErr != nil {
		return FeatureSignalContractStoreSnapshot{}, f.putErr
	}
	return snapshot, nil
}

func (f failingFeatureSignalContractStore) Watch(ctx context.Context) (<-chan FeatureSignalContractStoreSnapshot, error) {
	if f.watchErr != nil {
		return nil, f.watchErr
	}
	ch := make(chan FeatureSignalContractStoreSnapshot)
	close(ch)
	return ch, nil
}

func TestFeatureSignalContractStoreRoundtripAndWatch(t *testing.T) {
	now := time.Date(2026, 4, 8, 2, 35, 0, 0, time.UTC)
	seed := FeatureSignalContractStoreSnapshot{
		Revision:    7,
		GeneratedAt: now,
		Active: map[string]FeatureSignalContract{
			"k1": {
				RequiredFields:     []string{"feature_version"},
				SchemaVersion:      "v1.0.0",
				TrustedProducerIDs: []string{"p1"},
				MaxFreshnessMS:     1000,
				MaxDriftScore:      0.2,
			},
		},
		Meta: map[string]time.Time{
			"k1": now,
		},
		History: map[string][]FeatureSignalContractVersion{
			"k1": {
				{
					Version:            1,
					ContractKey:        "low|PRE_TOOL",
					StorageKey:         "k1",
					RiskTier:           RiskLow,
					Phase:              PhasePreTool,
					RequiredFields:     []string{"feature_version"},
					SchemaVersion:      "v1.0.0",
					TrustedProducerIDs: []string{"p1"},
					MaxFreshnessMS:     1000,
					MaxDriftScore:      0.2,
					Scope:              ScopeRef{OrgID: "org", WorkspaceID: "ws", ProjectID: "proj"},
					ContractHash:       "h1",
					Status:             "active",
					ActivationAt:       now,
					Reason:             "seed",
					Actor:              "system",
					CreatedAt:          now,
				},
			},
		},
		Rollbacks: map[string][]FeatureSignalContractRollbackRecord{
			"k1": {
				{
					RollbackID:             "rb1",
					ContractKey:            "low|PRE_TOOL",
					StorageKey:             "k1",
					Scope:                  ScopeRef{OrgID: "org", WorkspaceID: "ws", ProjectID: "proj"},
					PreviousVersion:        2,
					TargetVersion:          1,
					PreviousRequiredFields: []string{"feature_version", "feature_evidence_ref"},
					TargetRequiredFields:   []string{"feature_version"},
					PreviousContractHash:   "h2",
					TargetContractHash:     "h1",
					Reason:                 "rollback",
					Actor:                  "ops",
					CreatedAt:              now,
				},
			},
		},
		Scheduled: map[string][]FeatureSignalContractVersion{
			"k1": {
				{
					Version:            3,
					ContractKey:        "low|PRE_TOOL",
					StorageKey:         "k1",
					RiskTier:           RiskLow,
					Phase:              PhasePreTool,
					RequiredFields:     []string{"feature_version", "feature_evidence_ref"},
					SchemaVersion:      "v2.0.0",
					TrustedProducerIDs: []string{"p2"},
					MaxFreshnessMS:     800,
					MaxDriftScore:      0.15,
					Scope:              ScopeRef{OrgID: "org", WorkspaceID: "ws", ProjectID: "proj"},
					ContractHash:       "h3",
					Status:             "scheduled",
					ActivationAt:       now.Add(5 * time.Minute),
					Reason:             "rollout",
					Actor:              "ops",
					CreatedAt:          now,
				},
			},
		},
	}
	store := NewInMemoryFeatureSignalContractStore(8, seed)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	wch, err := store.Watch(ctx)
	if err != nil {
		t.Fatalf("watch: %v", err)
	}
	initial := <-wch
	if initial.Revision != 7 {
		t.Fatalf("unexpected initial revision: %d", initial.Revision)
	}

	s1, err := store.GetSnapshot(context.Background())
	if err != nil {
		t.Fatalf("get snapshot: %v", err)
	}
	s1.Active["k1"] = FeatureSignalContract{RequiredFields: []string{"mutated"}}
	s2, err := store.GetSnapshot(context.Background())
	if err != nil {
		t.Fatalf("get snapshot after mutate copy: %v", err)
	}
	if sameStringSet(s2.Active["k1"].RequiredFields, []string{"mutated"}) {
		t.Fatalf("store snapshot must be deep-cloned; mutation leaked")
	}

	commit, err := store.PutSnapshot(context.Background(), FeatureSignalContractStoreSnapshot{
		Revision:    1, // lower than current, store should still advance revision monotonically.
		GeneratedAt: now.Add(1 * time.Minute),
		Active:      s2.Active,
		Meta:        s2.Meta,
		History:     s2.History,
		Rollbacks:   s2.Rollbacks,
		Scheduled:   s2.Scheduled,
	})
	if err != nil {
		t.Fatalf("put snapshot: %v", err)
	}
	if commit.Revision <= 7 {
		t.Fatalf("expected monotonic store revision, got=%d", commit.Revision)
	}
	updated := <-wch
	if updated.Revision != commit.Revision {
		t.Fatalf("watch event revision mismatch: got=%d want=%d", updated.Revision, commit.Revision)
	}

	canceledCtx, canceled := context.WithCancel(context.Background())
	canceled()
	if _, err := store.GetSnapshot(canceledCtx); err == nil {
		t.Fatalf("expected get snapshot canceled error")
	}
	if _, err := store.PutSnapshot(canceledCtx, commit); err == nil {
		t.Fatalf("expected put snapshot canceled error")
	}
	if _, err := store.Watch(canceledCtx); err == nil {
		t.Fatalf("expected watch canceled error")
	}
}

func TestFeatureSignalContractRuntimeSyncErrorAndWatcherBranches(t *testing.T) {
	now := time.Date(2026, 4, 8, 2, 40, 0, 0, time.UTC)
	svcErr := NewKernel(Config{
		Clock: func() time.Time { return now },
		FeatureSignalContractStore: failingFeatureSignalContractStore{
			getErr:   errors.New("get-fail"),
			putErr:   errors.New("put-fail"),
			watchErr: errors.New("watch-fail"),
		},
	})

	svcErr.runtimeMu.Lock()
	if err := svcErr.syncContractCacheFromStoreLocked(context.Background()); err == nil {
		svcErr.runtimeMu.Unlock()
		t.Fatalf("expected sync cache error from failing get snapshot")
	}
	if err := svcErr.publishContractSnapshotLocked(now); err == nil {
		svcErr.runtimeMu.Unlock()
		t.Fatalf("expected publish snapshot error from failing put snapshot")
	}
	// apply snapshot branch coverage including version update.
	svcErr.applyContractStoreSnapshotLocked(FeatureSignalContractStoreSnapshot{
		Revision:    11,
		GeneratedAt: now,
		Active:      map[string]FeatureSignalContract{},
		Meta:        map[string]time.Time{},
		History:     map[string][]FeatureSignalContractVersion{},
		Rollbacks:   map[string][]FeatureSignalContractRollbackRecord{},
		Scheduled:   map[string][]FeatureSignalContractVersion{},
	})
	if svcErr.storeVersion != 11 {
		svcErr.runtimeMu.Unlock()
		t.Fatalf("expected store version from snapshot, got=%d", svcErr.storeVersion)
	}
	svcErr.runtimeMu.Unlock()

	if err := svcErr.StartFeatureSignalContractCacheWatcher(context.Background()); err == nil {
		t.Fatalf("expected watcher start error with failing watch backend")
	}

	store := NewInMemoryFeatureSignalContractStore(8, FeatureSignalContractStoreSnapshot{})
	svc := NewKernel(Config{
		Clock:                      func() time.Time { return now },
		FeatureSignalContractStore: store,
	})
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	if err := svc.StartFeatureSignalContractCacheWatcher(ctx); err != nil {
		t.Fatalf("start watcher: %v", err)
	}
	if err := svc.StartFeatureSignalContractCacheWatcher(ctx); err == nil {
		t.Fatalf("expected duplicate watcher start error")
	}
	svc.StopFeatureSignalContractCacheWatcher()

	if err := svc.StartFeatureSignalContractActivationWorker(ctx, 0, ""); err != nil {
		t.Fatalf("start activation worker with defaults: %v", err)
	}
	if err := svc.StartFeatureSignalContractActivationWorker(ctx, 10*time.Millisecond, "w2"); err == nil {
		t.Fatalf("expected duplicate activation worker start error")
	}
	svc.StopFeatureSignalContractActivationWorker()
}

func TestFeatureSignalContractRuntimeAdditionalBranches(t *testing.T) {
	now := time.Date(2026, 4, 8, 2, 45, 0, 0, time.UTC)
	svc := NewKernel(Config{
		Clock: func() time.Time { return now },
	})

	// syncContractCacheFromStoreLocked: no-store and zero-revision branches.
	svc.runtimeMu.Lock()
	origStoreVersion := svc.storeVersion
	svc.contractStore = nil
	if err := svc.syncContractCacheFromStoreLocked(context.Background()); err != nil {
		svc.runtimeMu.Unlock()
		t.Fatalf("sync with nil store should not fail: %v", err)
	}
	svc.contractStore = NewInMemoryFeatureSignalContractStore(4, FeatureSignalContractStoreSnapshot{})
	if err := svc.syncContractCacheFromStoreLocked(context.Background()); err != nil {
		svc.runtimeMu.Unlock()
		t.Fatalf("sync with zero-revision store should not fail: %v", err)
	}
	if svc.storeVersion != origStoreVersion {
		svc.runtimeMu.Unlock()
		t.Fatalf("store version should remain unchanged on zero-revision sync: got=%d want=%d", svc.storeVersion, origStoreVersion)
	}
	// apply snapshot with zero revision should not overwrite storeVersion.
	svc.applyContractStoreSnapshotLocked(FeatureSignalContractStoreSnapshot{
		Revision: 0,
		Active:   map[string]FeatureSignalContract{},
		Meta:     map[string]time.Time{},
		History:  map[string][]FeatureSignalContractVersion{},
		Rollbacks: map[string][]FeatureSignalContractRollbackRecord{
			"dummy": {},
		},
		Scheduled: map[string][]FeatureSignalContractVersion{},
	})
	if svc.storeVersion != origStoreVersion {
		svc.runtimeMu.Unlock()
		t.Fatalf("zero revision apply should not change store version: got=%d want=%d", svc.storeVersion, origStoreVersion)
	}
	svc.runtimeMu.Unlock()

	// scheduler path: now.IsZero and empty worker id normalization.
	res := svc.RunFeatureSignalContractSchedulerWithWorker(time.Time{}, "")
	if res.RanAt.IsZero() {
		t.Fatalf("scheduler should resolve zero time to clock time")
	}

	// scheduler publish error branch.
	svcErr := NewKernel(Config{
		Clock: func() time.Time { return now },
		FeatureSignalContractStore: failingFeatureSignalContractStore{
			putErr: errors.New("put-fail"),
		},
	})
	resErr := svcErr.RunFeatureSignalContractSchedulerWithWorker(now, "worker-x")
	if resErr.Activated != 0 || resErr.Pending != 0 {
		t.Fatalf("scheduler with store sync error should return zero result, got=%+v", resErr)
	}

	// Apply/sync populated snapshot to cover map-copy branches.
	populatedStore := NewInMemoryFeatureSignalContractStore(0, FeatureSignalContractStoreSnapshot{
		Revision:    21,
		GeneratedAt: now,
		Active: map[string]FeatureSignalContract{
			"pop::k": {
				RequiredFields:     []string{"feature_version", "feature_evidence_ref"},
				SchemaVersion:      "v9.0.0",
				TrustedProducerIDs: []string{"p9"},
				MaxFreshnessMS:     900,
				MaxDriftScore:      0.09,
			},
		},
		Meta: map[string]time.Time{
			"pop::k": now,
		},
		History: map[string][]FeatureSignalContractVersion{
			"pop::k": {
				{
					Version:            4,
					ContractKey:        "high|PRE_TOOL",
					StorageKey:         "pop::k",
					RiskTier:           RiskHigh,
					Phase:              PhasePreTool,
					RequiredFields:     []string{"feature_version"},
					SchemaVersion:      "v9.0.0",
					TrustedProducerIDs: []string{"p9"},
					MaxFreshnessMS:     900,
					MaxDriftScore:      0.09,
					Scope:              ScopeRef{OrgID: "org", WorkspaceID: "ws", ProjectID: "proj"},
					ContractHash:       "h-pop",
					Status:             "active",
					ActivationAt:       now,
					CreatedAt:          now,
				},
			},
		},
		Rollbacks: map[string][]FeatureSignalContractRollbackRecord{
			"pop::k": {
				{
					RollbackID:             "rb-pop",
					ContractKey:            "high|PRE_TOOL",
					StorageKey:             "pop::k",
					Scope:                  ScopeRef{OrgID: "org", WorkspaceID: "ws", ProjectID: "proj"},
					PreviousVersion:        5,
					TargetVersion:          4,
					PreviousRequiredFields: []string{"feature_version", "feature_evidence_ref"},
					TargetRequiredFields:   []string{"feature_version"},
					CreatedAt:              now,
				},
			},
		},
		Scheduled: map[string][]FeatureSignalContractVersion{
			"pop::k": {
				{
					Version:        5,
					ContractKey:    "high|PRE_TOOL",
					StorageKey:     "pop::k",
					RiskTier:       RiskHigh,
					Phase:          PhasePreTool,
					RequiredFields: []string{"feature_version", "feature_evidence_ref", "feature_producer_id"},
					Scope:          ScopeRef{OrgID: "org", WorkspaceID: "ws", ProjectID: "proj"},
					Status:         "scheduled",
					ActivationAt:   now.Add(5 * time.Minute),
					CreatedAt:      now,
				},
			},
		},
	})
	svcPop := NewKernel(Config{
		Clock:                      func() time.Time { return now },
		FeatureSignalContractStore: populatedStore,
	})
	svcPop.runtimeMu.Lock()
	if err := svcPop.syncContractCacheFromStoreLocked(context.Background()); err != nil {
		svcPop.runtimeMu.Unlock()
		t.Fatalf("sync populated snapshot: %v", err)
	}
	if svcPop.storeVersion != 21 {
		svcPop.runtimeMu.Unlock()
		t.Fatalf("expected synced store version=21, got=%d", svcPop.storeVersion)
	}
	if len(svcPop.featureSignalContractsScoped) == 0 || len(svcPop.featureSignalContractHistory) == 0 || len(svcPop.featureSignalContractRollbacks) == 0 || len(svcPop.featureSignalContractScheduled) == 0 {
		svcPop.runtimeMu.Unlock()
		t.Fatalf("expected populated contract cache from snapshot")
	}
	svcPop.runtimeMu.Unlock()
}

func TestFeatureSignalContractStoreWatchBufferDropBranch(t *testing.T) {
	now := time.Date(2026, 4, 8, 2, 50, 0, 0, time.UTC)
	store := NewInMemoryFeatureSignalContractStore(1, FeatureSignalContractStoreSnapshot{
		Revision:    1,
		GeneratedAt: now,
		Active: map[string]FeatureSignalContract{
			"k": {RequiredFields: []string{"feature_version"}},
		},
		Meta:      map[string]time.Time{"k": now},
		History:   map[string][]FeatureSignalContractVersion{},
		Rollbacks: map[string][]FeatureSignalContractRollbackRecord{},
		Scheduled: map[string][]FeatureSignalContractVersion{},
	})
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	ch, err := store.Watch(ctx)
	if err != nil {
		t.Fatalf("watch: %v", err)
	}
	// Do not read initial event so channel remains full.
	_, err = store.PutSnapshot(context.Background(), FeatureSignalContractStoreSnapshot{
		Revision:    2,
		GeneratedAt: now.Add(1 * time.Minute),
		Active: map[string]FeatureSignalContract{
			"k": {RequiredFields: []string{"feature_version", "feature_evidence_ref"}},
		},
		Meta:      map[string]time.Time{"k": now.Add(1 * time.Minute)},
		History:   map[string][]FeatureSignalContractVersion{},
		Rollbacks: map[string][]FeatureSignalContractRollbackRecord{},
		Scheduled: map[string][]FeatureSignalContractVersion{},
	})
	if err != nil {
		t.Fatalf("put snapshot 1: %v", err)
	}
	finalSnap, err := store.PutSnapshot(context.Background(), FeatureSignalContractStoreSnapshot{
		Revision:    3,
		GeneratedAt: now.Add(2 * time.Minute),
		Active: map[string]FeatureSignalContract{
			"k": {RequiredFields: []string{"feature_version", "feature_evidence_ref", "feature_producer_id"}},
		},
		Meta:      map[string]time.Time{"k": now.Add(2 * time.Minute)},
		History:   map[string][]FeatureSignalContractVersion{},
		Rollbacks: map[string][]FeatureSignalContractRollbackRecord{},
		Scheduled: map[string][]FeatureSignalContractVersion{},
	})
	if err != nil {
		t.Fatalf("put snapshot 2: %v", err)
	}

	// Channel should eventually expose latest snapshot despite full-buffer replacements.
	select {
	case got := <-ch:
		if got.Revision != finalSnap.Revision {
			t.Fatalf("expected latest revision from watch buffer drop path, got=%d want=%d", got.Revision, finalSnap.Revision)
		}
	case <-time.After(300 * time.Millisecond):
		t.Fatalf("timeout waiting watch snapshot")
	}
}

func TestRuntimeFeatureTrustContractEnforcement(t *testing.T) {
	now := time.Date(2026, 4, 8, 2, 30, 0, 0, time.UTC)
	scope := ScopeRef{OrgID: "org-trust", WorkspaceID: "ws-trust", ProjectID: "proj-trust"}
	svc := NewKernel(Config{
		Clock:                      func() time.Time { return now },
		RequireHighRiskContractPin: true,
	})
	contractView, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:           "*",
		Phase:              PhasePreTool,
		RequiredFields:     []string{"feature_version", "feature_schema_version", "feature_evidence_ref", "feature_producer_id"},
		SchemaVersion:      "v2.0.0",
		TrustedProducerIDs: []string{"trusted-producer"},
		MaxFreshnessMS:     1200,
		MaxDriftScore:      0.4,
		Reason:             "trust-policy",
		Scope:              scope,
	})
	if err != nil {
		t.Fatalf("publish trust contract: %v", err)
	}

	base := validRuntimeRequest()
	base.RiskTier = RiskHigh
	base.EffectType = EffectWrite
	base.FeatureContractScope = scope
	base.FeatureContractHashPin = contractView.ContractHash
	base.FeatureVersion = "fv-trust"
	base.FeatureSchemaVersion = "v2.0.0"
	base.FeatureEvidenceRef = "evidence://feature/fv-trust"
	base.FeatureProducerID = "trusted-producer"
	base.FeatureFreshnessMS = 800
	base.FeatureDriftScore = 0.2
	base.DecisionGraphID = "dg-trust"
	base.PolicyEngineAvailable = boolPtr(true)
	base.ApprovalSystemAvailable = true

	// Missing pin on high risk should fail closed when RequireHighRiskContractPin=true.
	noPin := base
	noPin.FeatureContractHashPin = ""
	outNoPin := svc.EvaluateRuntime(noPin)
	if outNoPin.Decision != DecisionFailClosed {
		t.Fatalf("expected fail closed when high-risk hash pin missing, got=%s", outNoPin.Decision)
	}

	// Schema mismatch should fail closed for high risk.
	schemaMismatch := base
	schemaMismatch.FeatureSchemaVersion = "v1.9.0"
	outSchema := svc.EvaluateRuntime(schemaMismatch)
	if outSchema.Decision != DecisionFailClosed {
		t.Fatalf("expected fail closed on schema mismatch, got=%s", outSchema.Decision)
	}

	// Producer trust mismatch should fail closed for high risk.
	producerMismatch := base
	producerMismatch.FeatureProducerID = "untrusted"
	outProducer := svc.EvaluateRuntime(producerMismatch)
	if outProducer.Decision != DecisionFailClosed {
		t.Fatalf("expected fail closed on producer mismatch, got=%s", outProducer.Decision)
	}

	// Freshness limit breach should fail closed for high risk.
	freshnessMismatch := base
	freshnessMismatch.FeatureFreshnessMS = 5000
	outFresh := svc.EvaluateRuntime(freshnessMismatch)
	if outFresh.Decision != DecisionFailClosed {
		t.Fatalf("expected fail closed on freshness contract breach, got=%s", outFresh.Decision)
	}

	// Drift limit breach should fail closed for high risk.
	driftMismatch := base
	driftMismatch.FeatureDriftScore = 0.9
	outDrift := svc.EvaluateRuntime(driftMismatch)
	if outDrift.Decision != DecisionFailClosed {
		t.Fatalf("expected fail closed on drift contract breach, got=%s", outDrift.Decision)
	}

	// Low risk uses review_required path for trust contract violation.
	low := base
	low.RiskTier = RiskLow
	low.FeatureProducerID = "untrusted"
	low.FeatureContractHashPin = ""
	outLow := svc.EvaluateRuntime(low)
	if outLow.Decision != DecisionReviewRequired {
		t.Fatalf("expected review_required for low-risk trust violation, got=%s", outLow.Decision)
	}
}

func TestContractSchedulerResultAndKeyMatchLevels(t *testing.T) {
	now := time.Date(2026, 4, 8, 3, 0, 0, 0, time.UTC)
	scope := ScopeRef{OrgID: "org-km", WorkspaceID: "ws-km", ProjectID: "proj-km"}
	svc := NewKernel(Config{
		Clock: func() time.Time { return now },
	})
	_, err := svc.PublishFeatureSignalContract(FeatureSignalContractPublishRequest{
		RiskTier:       RiskLow,
		Phase:          PhasePreResume,
		RequiredFields: []string{"feature_version"},
		Reason:         "scheduled",
		Scope:          scope,
		ActivateAt:     now.Add(15 * time.Minute),
	})
	if err != nil {
		t.Fatalf("publish scheduled contract: %v", err)
	}

	none := svc.RunFeatureSignalContractScheduler(now.Add(5 * time.Minute))
	if none.Activated != 0 || none.Pending == 0 {
		t.Fatalf("scheduler should not activate before due: %+v", none)
	}

	yes := svc.RunFeatureSignalContractScheduler(now.Add(16 * time.Minute))
	if yes.Activated == 0 {
		t.Fatalf("scheduler should activate due contract: %+v", yes)
	}

	if keyMatchLevel("low|PRE_TOOL", RiskLow, PhasePreTool) != "exact" {
		t.Fatalf("expected exact key match level")
	}
	if keyMatchLevel("low|*", RiskLow, PhasePreTool) != "risk_wildcard" {
		t.Fatalf("expected risk wildcard key match level")
	}
	if keyMatchLevel("*|PRE_TOOL", RiskLow, PhasePreTool) != "phase_wildcard" {
		t.Fatalf("expected phase wildcard key match level")
	}
	if keyMatchLevel("*|*", RiskLow, PhasePreTool) != "global_wildcard" {
		t.Fatalf("expected global wildcard key match level")
	}
	if keyMatchLevel("custom", RiskLow, PhasePreTool) != "unknown" {
		t.Fatalf("expected unknown key match level")
	}
}

